const items = $input.all();
const results = [];

for (const item of items) {
  const email = item.json;
  const fromRaw = email.From || '';
  const emailMatch = fromRaw.match(/<([^>]+)>/);
  const senderEmail = emailMatch ? emailMatch[1] : fromRaw;
  const subject = email.Subject || '';
  const text = email.snippet || '';

  const prompt = `Analyze the following email. Respond EXACTLY in this textual format (DO NOT use JSON):\n\nPRIORITY: [high/medium/low]\nSUMMARY: [summarize the sender's request in 1-2 sentences]\nDRAFT RESPONSE:\n[draft a polite and professional response in the SAME LANGUAGE as the original email. Do NOT include placeholder signatures like '[Your Name]' or 'Your Name'. End the response with 'Cordiali saluti.' if the email is in Italian, or 'Best regards.' if in English]\n\nDo not hallucinate information. Base your response strictly on the provided text.\n\nSENDER: ${senderEmail}\nSUBJECT: ${subject}\nBODY: ${text}`;

  try {
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: 'http://argos-api:8000/run',
      body: {
        task: prompt,
        max_steps: 3,
        require_confirmation: false
      },
      json: true,
      timeout: 60000
    });

    const result = response.result || '';

    const impMatch = result.match(/PRIORITY:\s*(\S+)/i);
    const importanza = impMatch ? impMatch[1].toLowerCase() : 'medium';

    if (importanza.includes('low') || importanza.includes('bassa')) continue;

    const riasMatch = result.match(/SUMMARY:\s*(.+?)(?=\nDRAFT|$)/is);
    const riassunto = riasMatch ? riasMatch[1].trim() : '';

    const draftMatch = result.match(/DRAFT RESPONSE:\s*\n?([\s\S]*)/i);
    const draftPlain = draftMatch ? draftMatch[1].trim() : result;

    const draftHtml = '<div style="font-family: Arial, sans-serif; font-size: 14px; line-height: 1.6;">' +
      draftPlain.split('\n\n').map(p => '<p style="margin: 0 0 12px 0;">' + p.replace(/\n/g, '<br>') + '</p>').join('') +
      '</div>';

    results.push({ json: { 
      senderEmail, 
      subject, 
      messageId: email.id || '', 
      threadId: email.threadId || '', 
      importanza, 
      riassunto, 
      draft: draftPlain, 
      draftHtml, 
      fromRaw 
    }});
  } catch(e) {
    console.error("ARGOS API Execution Error:", e);
  }
}

return results;

